// ─── Helper: update YAML frontmatter ────────────────────────────────────

function updateFrontmatter(raw, meta) {
  const fmEnd = raw.indexOf("---", 3);
  if (fmEnd === -1) throw new Error("No frontmatter found");

  const body = raw.slice(fmEnd + 3);
  const fm = raw.slice(3, fmEnd);

  // Extract existing fields to preserve
  const ex = {};
  for (const key of ["slice_id", "status", "start", "end", "timezone", "closedBy", "related_slices"]) {
    const re = new RegExp(`^${key}:\\s*(.+)$`, "m");
    const m = fm.match(re);
    if (m) ex[key] = m[1].trim().replace(/^["']|["']$/g, "");
  }

  // Fix timezone for 2026/07/06 (was Asia/Shanghai from a live session leak)
  if (ex.slice_id === "2026-07-06" && ex.timezone === "Asia/Shanghai") {
    ex.timezone = "America/Chicago";
  }

  const lines = [];
  lines.push("---");
  lines.push(`slice_id: ${ex.slice_id || ""}`);
  lines.push(`focus: ${meta.focus}`);
  lines.push(`status: ${ex.status || "closed"}`);
  lines.push(`start: "${ex.start || ""}"`);
  if (ex.end) lines.push(`end: "${ex.end}"`);
  if (ex.timezone) lines.push(`timezone: ${ex.timezone}`);
  lines.push(`summary: ${meta.summary}`);

  if (meta.decisions && meta.decisions.length > 0) {
    lines.push("decisions:");
    for (const d of meta.decisions) lines.push(`  - ${d}`);
  } else {
    lines.push("decisions: []");
  }

  if (meta.open_loops && meta.open_loops.length > 0) {
    lines.push("open_loops:");
    for (const o of meta.open_loops) lines.push(`  - ${o}`);
  } else {
    lines.push("open_loops: []");
  }

  if (meta.tags && meta.tags.length > 0) {
    lines.push("tags:");
    for (const t of meta.tags) lines.push(`  - ${t}`);
  } else {
    lines.push("tags: []");
  }

  lines.push(`emotional_tone: ${meta.emotional_tone}`);

  if (ex.related_slices) lines.push(`related_slices: ${ex.related_slices}`);
  if (ex.closedBy) lines.push(`closedBy: ${ex.closedBy}`);

  lines.push("---");

  return lines.join("\n") + body;
}

// ─── Main ────────────────────────────────────────────────────────────────

let updatedFiles = 0;
let updatedIndices = 0;

for (const [relPath, meta] of Object.entries(METADATA)) {
  const filePath = join(DEMO, relPath + ".md");
  if (!existsSync(filePath)) { console.error(`  NOT FOUND: ${filePath}`); continue; }
  const raw = readFileSync(filePath, "utf-8");
  const updated = updateFrontmatter(raw, meta);
  writeFileSync(filePath, updated, "utf-8");
  updatedFiles++;
}

console.log(`Updated ${updatedFiles} slice files.`);

// ─── Update _index.json files ────────────────────────────────────────────

const byMonth = {};
for (const [relPath, meta] of Object.entries(METADATA)) {
  const parts = relPath.split("/");
  const yearMonth = `${parts[0]}-${parts[1]}`;
  if (!byMonth[yearMonth]) byMonth[yearMonth] = [];
  byMonth[yearMonth].push({ day: parts[2], meta });
}

for (const [yearMonth, entries] of Object.entries(byMonth)) {
  const [year, month] = yearMonth.split("-");
  const indexPath = join(DEMO, year, month, "_index.json");
  if (!existsSync(indexPath)) { console.error(`  INDEX NOT FOUND: ${indexPath}`); continue; }
  const index = JSON.parse(readFileSync(indexPath, "utf-8"));
  for (const entry of entries) {
    const slice = index.slices.find(s => s.id === entry.day);
    if (slice) {
      slice.focus = entry.meta.focus;
      slice.summary = entry.meta.summary;
      slice.decisions = entry.meta.decisions;
      slice.open_loops = entry.meta.open_loops;
      slice.tags = entry.meta.tags;
    }
  }
  writeFileSync(indexPath, JSON.stringify(index, null, 2) + "\n", "utf-8");
  updatedIndices++;
}

console.log(`Updated ${updatedIndices} index files.`);
console.log("Done!");
